class Solution {
public:
    long long maxGCDScore(vector<int>& nums, int k) {
        int n = nums.size();
        vector<vector<int>> gcds(n, vector<int>(n));
        for (int i = 0; i < n; ++i) {
            gcds[i][i] = nums[i];
            for (int j = i - 1; j >= 0; --j) {
                gcds[j][i] = gcd(gcds[j][i - 1], nums[i]);
            }
        }

        long long res = 0;
        for (int i = 0; i < n; ++i) {
            for (int j = i; j < n; ++j) {
                int g = gcds[i][j];
                int len = j - i + 1;
                long long score = (long long)g * len;
                if (len <= k) {
                    res = max(res, score * 2);
                } else if (k > 0) {
                    res = max(res, score);
                }
            }
        }

        for (int i = 0; i < n; ++i) {
            res = max(res, (long long)nums[i] * 2);
        }

        return res;
    }

    int gcd(int a, int b) {
        while (b) {
            int t = b;
            b = a % b;
            a = t;
        }
        return a;
    }
};
